import{_ as e,o as t,c as a,ae as o}from"./chunks/framework.CyZiF_rV.js";const m=JSON.parse('{"title":"Подпись XAdES","description":"","frontmatter":{},"headers":[],"relativePath":"ru/auth/podpis-xades.md","filePath":"ru/auth/podpis-xades.md"}'),d={name:"ru/auth/podpis-xades.md"};function l(w,r,h,s,i,n){return t(),a("div",null,[...r[0]||(r[0]=[o('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/auth/podpis-xades.md" target="_blank" rel="noreferrer">auth/podpis-xades.md</a></p></blockquote><h1 id="подпись-xades" tabindex="-1">Подпись XAdES <a class="header-anchor" href="#подпись-xades" aria-label="Permalink to &quot;Подпись XAdES&quot;">​</a></h1><p><a href="https://www.w3.org/TR/XAdES/" target="_blank" rel="noreferrer">https://www.w3.org/TR/XAdES/</a></p><h2 id="технические-параметры-подписи-xades" tabindex="-1">Технические параметры подписи XAdES <a class="header-anchor" href="#технические-параметры-подписи-xades" aria-label="Permalink to &quot;Технические параметры подписи XAdES&quot;">​</a></h2><h3 id="допустимые-форматы-подписи" tabindex="-1">Допустимые форматы подписи <a class="header-anchor" href="#допустимые-форматы-подписи" aria-label="Permalink to &quot;Допустимые форматы подписи&quot;">​</a></h3><ul><li><strong>охватываемый</strong> (enveloped)</li><li><strong>охватывающий</strong> (enveloping)</li></ul><p>Подпись в внешнем формате (<strong>detached</strong>) не принимается.</p><h3 id="допустимые-преобразования-содержащиеся-в-подписи-xades" tabindex="-1">Допустимые преобразования, содержащиеся в подписи XAdES <a class="header-anchor" href="#допустимые-преобразования-содержащиеся-в-подписи-xades" aria-label="Permalink to &quot;Допустимые преобразования, содержащиеся в подписи XAdES&quot;">​</a></h3><ul><li><a href="http://www.w3.org/TR/1999/REC-xpath-19991116" target="_blank" rel="noreferrer">http://www.w3.org/TR/1999/REC-xpath-19991116</a> - not(ancestor-or-self::ds:Signature)</li><li><a href="http://www.w3.org/2002/06/xmldsig-filter2" target="_blank" rel="noreferrer">http://www.w3.org/2002/06/xmldsig-filter2</a></li><li><a href="http://www.w3.org/2000/09/xmldsig#enveloped-signature" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#enveloped-signature</a></li><li><a href="http://www.w3.org/2000/09/xmldsig#base64" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#base64</a></li><li><a href="http://www.w3.org/2006/12/xml-c14n11" target="_blank" rel="noreferrer">http://www.w3.org/2006/12/xml-c14n11</a></li><li><a href="http://www.w3.org/2006/12/xml-c14n11#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/2006/12/xml-c14n11#WithComments</a></li><li><a href="http://www.w3.org/2001/10/xml-exc-c14n#" target="_blank" rel="noreferrer">http://www.w3.org/2001/10/xml-exc-c14n#</a></li><li><a href="http://www.w3.org/2001/10/xml-exc-c14n#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/2001/10/xml-exc-c14n#WithComments</a></li><li><a href="http://www.w3.org/TR/2001/REC-xml-c14n-20010315" target="_blank" rel="noreferrer">http://www.w3.org/TR/2001/REC-xml-c14n-20010315</a></li><li><a href="http://www.w3.org/TR/2001/REC-xml-c14n-20010315#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/TR/2001/REC-xml-c14n-20010315#WithComments</a></li></ul><h3 id="принятые-профили-xades" tabindex="-1">Принятые профили XAdES <a class="header-anchor" href="#принятые-профили-xades" aria-label="Permalink to &quot;Принятые профили XAdES&quot;">​</a></h3><ul><li>XAdES-BES</li><li>XAdES-EPES</li><li>XAdES-T</li><li>XAdES-LT</li><li>XAdES-C</li><li>XAdES-X</li><li>XAdES-XL</li><li>XAdES-A</li><li>XAdES-ERS</li><li>XAdES-BASELINE-B</li><li>XAdES-BASELINE-T</li><li>XAdES-BASELINE-LT</li><li>XAdES-BASELINE-LTA</li></ul><h3 id="алгоритм-подписи-signedinfo-ds-signaturemethod" tabindex="-1">Алгоритм подписи SignedInfo (<code>ds:SignatureMethod</code>) <a class="header-anchor" href="#алгоритм-подписи-signedinfo-ds-signaturemethod" aria-label="Permalink to &quot;Алгоритм подписи SignedInfo (`ds:SignatureMethod`)&quot;">​</a></h3><p><strong>RSASSA-PKCS1-v1_5</strong><br><a href="http://www.w3.org/2000/09/xmldsig#rsa-sha1" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#rsa-sha1</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha384</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha512</a></p><p>Минимальная длина ключа: 2048 бит</p><p><strong>RSASSA-PSS</strong><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha1-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha1-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha256-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha256-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha384-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha384-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha512-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha512-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-256-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-256-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-384-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-384-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-512-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-512-rsa-MGF1</a></p><p>Минимальная длина ключа: 2048 бит</p><p><strong>ECDSA</strong><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha1" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha1</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha384</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha512</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-256" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-256</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-384" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-384</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-512" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-512</a></p><p>Минимальный размер кривой: 256 бит</p><blockquote><p>Для ECDSA значение <code>SignatureValue</code> кодируется как <code>R || S</code> (fixed-field concatenation) согласно XML Signature (XMLDSIG) 1.1 / <a href="https://datatracker.ietf.org/doc/html/rfc4050#section-3.3" target="_blank" rel="noreferrer">RFC 4050</a>.</p></blockquote><h3 id="алгоритмы-хеширования-в-ссылках-digestmethod" tabindex="-1">Алгоритмы хеширования в ссылках (<code>DigestMethod</code>) <a class="header-anchor" href="#алгоритмы-хеширования-в-ссылках-digestmethod" aria-label="Permalink to &quot;Алгоритмы хеширования в ссылках (`DigestMethod`)&quot;">​</a></h3><p><code>DigestMethod</code> относится к хешу данных, указанных ссылками в <code>SignedInfo</code> (т.е. <code>SignedInfo / Reference / DigestMethod</code>) и не зависит от <code>SignatureMethod</code> (алгоритма подписи <code>SignedInfo</code>).</p><p>Те же алгоритмы хеширования используются также для вычисления хешей квалифицирующих свойств, в частности хеша сертификата в <code>SigningCertificate / CertDigest / DigestMethod</code>.</p><p><a href="http://www.w3.org/2000/09/xmldsig#sha1" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#sha1</a><br><a href="http://www.w3.org/2001/04/xmlenc#sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmlenc#sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#sha384</a><br><a href="http://www.w3.org/2001/04/xmlenc#sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmlenc#sha512</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-256" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-256</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-384" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-384</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-512" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-512</a></p><h3 id="разрешенные-типы-сертификатов" tabindex="-1">Разрешенные типы сертификатов <a class="header-anchor" href="#разрешенные-типы-сертификатов" aria-label="Permalink to &quot;Разрешенные типы сертификатов&quot;">​</a></h3><p>Разрешенные типы сертификатов в подписи XAdES:</p><ul><li>Квалифицированный сертификат физического лица – содержащий номер PESEL или NIP лица, имеющего полномочия действовать от имени компании,</li><li>Квалифицированный сертификат организации (так называемая корпоративная печать) - содержащий номер NIP,</li><li>Профиль Доверенный (ePUAP) – позволяет подписать документ; используется физическими лицами,</li><li>Внутренний сертификат KSeF – выдаваемый системой KSeF. Данный сертификат не является квалифицированным сертификатом, но принимается в процессе аутентификации.</li></ul><p><strong>Квалифицированный сертификат</strong> – сертификат, выданный квалифицированным поставщиком доверенных услуг, включенным в европейский реестр <a href="https://eidas.ec.europa.eu/efda/trust-services/browse/eidas/tls" target="_blank" rel="noreferrer">EU Trusted List (EUTL)</a>, в соответствии с регламентом eIDAS. В KSeF принимаются квалифицированные сертификаты, выданные в Польше и в других государствах-членах Европейского Союза.</p><h3 id="обязательные-атрибуты-квалифицированных-сертификатов" tabindex="-1">Обязательные атрибуты квалифицированных сертификатов <a class="header-anchor" href="#обязательные-атрибуты-квалифицированных-сертификатов" aria-label="Permalink to &quot;Обязательные атрибуты квалифицированных сертификатов&quot;">​</a></h3><h4 id="сертификаты-квалифицированнои-подписи-выдаваемые-для-физических-лиц" tabindex="-1">Сертификаты квалифицированной подписи (выдаваемые для физических лиц) <a class="header-anchor" href="#сертификаты-квалифицированнои-подписи-выдаваемые-для-физических-лиц" aria-label="Permalink to &quot;Сертификаты квалифицированной подписи (выдаваемые для физических лиц)&quot;">​</a></h4><p>Обязательные атрибуты субъекта:<br></p><table tabindex="0"><thead><tr><th>Идентификатор (OID)</th><th>Название</th><th>Значение</th></tr></thead><tbody><tr><td>2.5.4.42</td><td>givenName</td><td>имя</td></tr><tr><td>2.5.4.4</td><td>surname</td><td>фамилия</td></tr><tr><td>2.5.4.5</td><td>serialNumber</td><td>серийный номер</td></tr><tr><td>2.5.4.3</td><td>commonName</td><td>общее название владельца сертификата</td></tr><tr><td>2.5.4.6</td><td>countryName</td><td>название страны, код ISO 3166</td></tr></tbody></table><p>Распознаваемые шаблоны атрибута <code>serialNumber</code>:<br><strong>(PNOPL|PESEL).*?(?&lt;number&gt;\\d{11})</strong><br><strong>(TINPL|NIP).*?(?&lt;number&gt;\\d{10})</strong><br></p><h4 id="сертификаты-квалифицированнои-печати-выдаваемые-для-организации" tabindex="-1">Сертификаты квалифицированной печати (выдаваемые для организаций) <a class="header-anchor" href="#сертификаты-квалифицированнои-печати-выдаваемые-для-организации" aria-label="Permalink to &quot;Сертификаты квалифицированной печати (выдаваемые для организаций)&quot;">​</a></h4><p>Обязательные атрибуты субъекта:<br></p><table tabindex="0"><thead><tr><th>Идентификатор (OID)</th><th>Название</th><th>Значение</th></tr></thead><tbody><tr><td>2.5.4.10</td><td>organizationName</td><td>полное формальное название субъекта, для которого выдается сертификат</td></tr><tr><td>2.5.4.97</td><td>organizationIdentifier</td><td>идентификатор субъекта</td></tr><tr><td>2.5.4.3</td><td>commonName</td><td>общее название организации</td></tr><tr><td>2.5.4.6</td><td>countryName</td><td>название страны, код ISO 3166</td></tr></tbody></table><p>Недопустимые атрибуты субъекта:</p><table tabindex="0"><thead><tr><th>Идентификатор (OID)</th><th>Название</th><th>Значение</th></tr></thead><tbody><tr><td>2.5.4.42</td><td>givenName</td><td>имя</td></tr><tr><td>2.5.4.4</td><td>surname</td><td>фамилия</td></tr></tbody></table><p>Распознаваемые шаблоны атрибута <code>organizationIdentifier</code>:<br><strong>(VATPL).*?(?&lt;number&gt;\\d{10})</strong><br></p><h3 id="отпечаток-сертификата" tabindex="-1">Отпечаток сертификата <a class="header-anchor" href="#отпечаток-сертификата" aria-label="Permalink to &quot;Отпечаток сертификата&quot;">​</a></h3><p>В случае квалифицированных сертификатов, не имеющих соответствующих идентификаторов, записанных в атрибуте субъекта OID.2.5.4.5, возможна аутентификация таким сертификатом после предварительного предоставления прав на хеш SHA-256 (так называемый отпечаток) этого сертификата.</p><p>Связанные документы:</p><ul><li><a href="./../uwierzytelnianie.html">Аутентификация</a></li></ul>',42)])])}const p=e(d,[["render",l]]);export{m as __pageData,p as default};
